    for (int p = 1; p <= n - 2; ++p) {
        bool first_ok = true;
        for (int i = 0; i < p; ++i) {
            if (nums[i] >= nums[i + 1]) {
                first_ok = false;
                break;
            }
        }
        if (!first_ok) continue;
        for (int q = p + 1; q <= n - 2; ++q) {
            bool second_ok = true;
            for (int i = p; i < q; ++i) {
                if (nums[i] <= nums[i + 1]) {
                    second_ok = false;
                    break;
                }
            }
            if (!second_ok) continue;
            bool third_ok = true;
            for (int i = q; i < n - 1; ++i) {
                if (nums[i] >= nums[i + 1]) {
                    third_ok = false;
                    break;
                }
            }
            if (third_ok) return true;
        }
    }
    return false;
}
